export function getLevelFromXP(xp: number, rules: RuleSet): number {
  const table = rules.xp_table; // Expect [0, 300, 900...]
  for (let i = table.length - 1; i >= 0; i--) {
    if (xp >= table[i]) return i + 1;
  }
  return 1;
}

