Description:

Checks Line of Sight using Bresenham's Algorithm (3D Step).
Returns true if NO obstacles are found between start and end.

Signature:
export function hasLineOfSight(start: Point3D, end: Point3D, isBlocked: CollisionCheck): boolean {
  let { x: x0, y: y0, z: z0 } = start;
  const { x: x1, y: y1, z: z1 } = end;

  const dx = Math.abs(x1 - x0);
  const dy = Math.abs(y1 - y0);
  const dz = Math.abs(z1 - z0);

  const sx = x0 < x1 ? 1 : -1;
  const sy = y0 < y1 ? 1 : -1;
  const sz = z0 < z1 ? 1 : -1;

  // Driving axis is the one with max difference
  if (dx >= dy && dx >= dz) {
    let p1 = 2 * dy - dx;
    let p2 = 2 * dz - dx;
    while (x0 !== x1) {
      x0 += sx;
      if (p1 >= 0) {
        y0 += sy;
        p1 -= 2 * dx;
      }
      if (p2 >= 0) {
        z0 += sz;
        p2 -= 2 * dx;
      }
      p1 += 2 * dy;
      p2 += 2 * dz;
      if (isBlocked({ x: x0, y: y0, z: z0 })) return false;
    }
  } else if (dy >= dx && dy >= dz) {
    let p1 = 2 * dx - dy;
    let p2 = 2 * dz - dy;
    while (y0 !== y1) {
      y0 += sy;
      if (p1 >= 0) {
        x0 += sx;
        p1 -= 2 * dy;
      }
      if (p2 >= 0) {
        z0 += sz;
        p2 -= 2 * dy;
      }
      p1 += 2 * dx;
      p2 += 2 * dz;
      if (isBlocked({ x: x0, y: y0, z: z0 })) return false;
    }
  } else {
    let p1 = 2 * dy - dz;
    let p2 = 2 * dx - dz;
    while (z0 !== z1) {
      z0 += sz;
      if (p1 >= 0) {
        y0 += sy;
        p1 -= 2 * dz;
      }
      if (p2 >= 0) {
        x0 += sx;
        p2 -= 2 * dz;
      }
      p1 += 2 * dy;
      p2 += 2 * dx;
      if (isBlocked({ x: x0, y: y0, z: z0 })) return false;
    }
  }

  return true;
}

